package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import java.util.List;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVParserTest {

    private CSVParser parser;
    private Lexer lexerMock;
    private Token token;

    @BeforeEach
    void setUp() throws Exception {
        // Mock dependencies
        lexerMock = mock(Lexer.class);

        // Create a real Token instance to be reused by parser
        token = new Token();

        // Create CSVFormat mock or real instance as needed (can be null for this test)
        CSVFormat format = mock(CSVFormat.class);

        // Use reflection to create CSVParser instance with mocked Lexer and Token
        parser = new CSVParser(new StringReader(""), format);

        // Inject mocked lexer and reusableToken by reflection
        setField(parser, "lexer", lexerMock);
        setField(parser, "reusableToken", token);

        // Initialize headerMap and recordNumber for test stability
        setField(parser, "headerMap", null);
        setField(parser, "recordNumber", 0L);
    }

    @Test
    void testNextRecord_withTokensAndEORECORD() throws IOException {
        // Setup token sequence: TOKEN, TOKEN, EORECORD
        doAnswer(invocation -> {
            token.type = Token.Type.TOKEN;
            token.content = "value1";
            return null;
        }).doAnswer(invocation -> {
            token.type = Token.Type.TOKEN;
            token.content = "value2";
            return null;
        }).doAnswer(invocation -> {
            token.type = Token.Type.EORECORD;
            token.content = "value3";
            return null;
        }).when(lexerMock).nextToken(token);

        // Spy on addRecordValue to add values to record list
        CSVParser spyParser = spy(parser);
        doAnswer(invocation -> {
            List<String> record = (List<String>) getField(spyParser, "record");
            Token reusableToken = (Token) getField(spyParser, "reusableToken");
            record.add(reusableToken.content);
            return null;
        }).when(spyParser).addRecordValue();

        CSVRecord record = spyParser.nextRecord();

        assertNotNull(record);
        assertEquals(3, record.size());
        assertEquals("value1", record.get(0));
        assertEquals("value2", record.get(1));
        assertEquals("value3", record.get(2));
        assertEquals(1, spyParser.getRecordNumber());
    }

    @Test
    void testNextRecord_withEOF_andIsReadyTrue() throws IOException {
        doAnswer(invocation -> {
            token.type = Token.Type.EOF;
            token.isReady = true;
            token.content = "endValue";
            return null;
        }).when(lexerMock).nextToken(token);

        CSVParser spyParser = spy(parser);
        doAnswer(invocation -> {
            List<String> record = (List<String>) getField(spyParser, "record");
            Token reusableToken = (Token) getField(spyParser, "reusableToken");
            record.add(reusableToken.content);
            return null;
        }).when(spyParser).addRecordValue();

        CSVRecord record = spyParser.nextRecord();

        assertNotNull(record);
        assertEquals(1, record.size());
        assertEquals("endValue", record.get(0));
        assertEquals(1, spyParser.getRecordNumber());
    }

    @Test
    void testNextRecord_withEOF_andIsReadyFalse_returnsNull() throws IOException {
        doAnswer(invocation -> {
            token.type = Token.Type.EOF;
            token.isReady = false;
            return null;
        }).when(lexerMock).nextToken(token);

        CSVRecord record = parser.nextRecord();

        assertNull(record);
    }

    @Test
    void testNextRecord_withInvalidToken_throwsIOException() throws IOException {
        doAnswer(invocation -> {
            token.type = Token.Type.INVALID;
            return null;
        }).when(lexerMock).nextToken(token);

        IOException exception = assertThrows(IOException.class, () -> parser.nextRecord());
        assertTrue(exception.getMessage().contains("invalid parse sequence"));
    }

    @Test
    void testNextRecord_withComments() throws IOException {
        // Sequence: COMMENT, COMMENT, EORECORD
        doAnswer(invocation -> {
            token.type = Token.Type.COMMENT;
            token.content = "comment1";
            return null;
        }).doAnswer(invocation -> {
            token.type = Token.Type.COMMENT;
            token.content = "comment2";
            return null;
        }).doAnswer(invocation -> {
            token.type = Token.Type.EORECORD;
            token.content = "value";
            return null;
        }).when(lexerMock).nextToken(token);

        CSVParser spyParser = spy(parser);
        doAnswer(invocation -> {
            List<String> record = (List<String>) getField(spyParser, "record");
            Token reusableToken = (Token) getField(spyParser, "reusableToken");
            record.add(reusableToken.content);
            return null;
        }).when(spyParser).addRecordValue();

        CSVRecord record = spyParser.nextRecord();

        assertNotNull(record);
        assertEquals(1, record.size());
        assertEquals("value", record.get(0));
        assertEquals("comment1\ncomment2", record.getComment());
    }

    // Utility methods for reflection
    private void setField(Object target, String fieldName, Object value) throws Exception {
        java.lang.reflect.Field field = CSVParser.class.getDeclaredField(fieldName);
        field.setAccessible(true);
        field.set(target, value);
    }

    private Object getField(Object target, String fieldName) throws Exception {
        java.lang.reflect.Field field = CSVParser.class.getDeclaredField(fieldName);
        field.setAccessible(true);
        return field.get(target);
    }
}
